import{_ as a,o as e,c as l,a2 as i}from"./chunks/framework.DnrXFDHb.js";const d=JSON.parse('{"title":"CoPoS 全產業鏈深度研究：03 台股供應鏈地圖","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/CoPoS/03_台股供應鏈.md","filePath":"Deep32Q知識庫/產業洞察/CoPoS/03_台股供應鏈.md"}'),t={name:"Deep32Q知識庫/產業洞察/CoPoS/03_台股供應鏈.md"};function r(n,o,s,h,P,_){return e(),l("div",null,[...o[0]||(o[0]=[i('<h1 id="copos-全產業鏈深度研究-03-台股供應鏈地圖" tabindex="-1">CoPoS 全產業鏈深度研究：03 台股供應鏈地圖 <a class="header-anchor" href="#copos-全產業鏈深度研究-03-台股供應鏈地圖" aria-label="Permalink to &quot;CoPoS 全產業鏈深度研究：03 台股供應鏈地圖&quot;">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>CoPoS 帶來的不只是新技術，而是一整套設備、檢測、材料與載具需求的結構性變化。根據台灣產業媒體與法人整理，台積電首波 CoPoS 供應鏈已大致敲定，包含 13 家台灣廠商與多家國際設備大廠。</p><p>這波受惠廠商主要可分為幾類：濕製程與清洗、熱製程與烘烤、AOI／檢測／量測、自動化搬運與載具，以及測試設備。其中，台廠在先進封裝供應鏈的角色，正從過去的週邊輔助，升級為關鍵製程節點的直接參與者。</p><p>值得注意的是，CoWoS 與 CoPoS 供應鏈高度重疊，但 CoPoS 對翹曲控制、大面板對位、高密度清洗與更高密度檢測的需求更強，因此部分廠商的關鍵性可能進一步提升。</p><h2 id="事實與數據" tabindex="-1">事實與數據 <a class="header-anchor" href="#事實與數據" aria-label="Permalink to &quot;事實與數據&quot;">​</a></h2><ul><li>經濟日報與法人報導指出，台積電 CoPoS 首波設備供應鏈包含 13 家台廠：家登（3680）、均華（6640）、弘塑（3131）、辛耘（3583）、志聖（2467）、印能科技（7734）、晶彩科（3535）、大量（3167）、致茂（2360）、倍利科（7822），以及未上市的佳宸、亞智科技、力鼎。來源：經濟日報。</li><li>產業討論進一步將這 13 家台廠分類為：濕製程（弘塑、辛耘）、熱製程（志聖、印能）、AOI 檢測（大量、倍利科、晶彩科）、自動化與搬運（家登、均華）、測試（致茂）。來源：Instagram／法人與產業筆記整理。</li><li>家登除光罩盒外，也被市場點名切入 CoWoS／CoPoS 晶圓載具與面板載具角色。來源：口袋證券等市場討論。</li><li>印能則被市場與媒體點名在先進封裝除泡設備具獨家性，並已表態佈局 WMCM 與 CoPoS。來源：PTT／產業討論。</li><li>隨著嘉義 AP7 從 2025 年第三季底開始陸續進機，法人預期相關供應鏈從 2026 年起將進入較明顯設備出貨與認證高峰。來源：經濟日報。</li></ul><h2 id="產業意涵" tabindex="-1">產業意涵 <a class="header-anchor" href="#產業意涵" aria-label="Permalink to &quot;產業意涵&quot;">​</a></h2><p>對台股投資而言，CoPoS 的投資邏輯已經從「題材想像」轉向「工程定案」與「供應鏈收斂」。未來觀察重點不在於誰「可能」入列，而在於誰已經拿到關鍵規格、獨家位置與長期維護訂單。</p><p>更進一步看，若 CoPoS 成為 AI GPU 的標準封裝方向，那麼設備商的價值將不再只是單次出貨，而是長期的服務、升級、耗材與良率優化支援。這類「持續性收入」邏輯，是先進封裝設備股最值得追蹤的中長期故事。</p><h2 id="來源引用" tabindex="-1">來源引用 <a class="header-anchor" href="#來源引用" aria-label="Permalink to &quot;來源引用&quot;">​</a></h2><ul><li>經濟日報，《台積電先進封裝技術升級 首波 CoPoS 供應鏈出爐》</li><li>BusinessTech / 商周，《CoPoS 是什麼？概念股有哪些？台積電下一代先進封裝技術全解析》</li><li>Instagram／法人與投資筆記整理，《CoPoS 台廠供應鏈地圖》</li><li>PTT Stock 版引述供應鏈報導，《台積電 CoPoS 設備供應鏈上膛》</li></ul><h2 id="風險與不確定性提醒" tabindex="-1">風險與不確定性提醒 <a class="header-anchor" href="#風險與不確定性提醒" aria-label="Permalink to &quot;風險與不確定性提醒&quot;">​</a></h2><ul><li>供應鏈名單可能隨台積電工程調整而變動，非正式名單不一定等於長期合作關係。</li><li>部分公司受惠程度取決於是否為獨家、高單價或高維護需求，不見得每家都受惠相同。</li><li>設備訂單若集中在試產階段，短期股價催化劑明顯，但長期營收貢獻仍取決於量產進度。</li><li>國際設備商若取得更多關鍵位置，台廠仍可能面臨替代或價格壓力。</li></ul>',14)])])}const S=a(t,[["render",r]]);export{d as __pageData,S as default};
